text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 공개 릴리스 목표는 금요일 15:00 KST이다.",
        "conditions": [
          "스모크 테스트 통과 필요"
        ]
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "topic": "smoke-theme-pack.mjs 처리 방식",
        "proposal": "packageName mismatch를 무시하도록 smoke-theme-pack.mjs를 변경하자",
        "result": "거부됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "수요일 릴리스 제안",
        "detail": "수요일 릴리스는 내부 스트레치 골로만 언급되었고 확정 일정이 아니다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "detail": "목요일까지 가능하면 검토하자는 의견은 있었지만 확정 소유자는 지정되지 않았다."
      },
      {
        "topic": "수요일 내부 스트레치 골의 릴리스 노트 기재 여부",
        "detail": "답이 결정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "내부 수요일 스트레치 골을 릴리스 노트에 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "미착수",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "미착수",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "소유자 미지정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 통과 여부를 먼저 확인한다.",
      "스모크 결과가 나오면 Hara의 tarball 경로 점검 필요 여부와 결과를 확인한다.",
      "Doyun의 failure triage note 작성 완료 여부를 확인한다.",
      "README 설치 단계 검토의 실제 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자에 대한 답변을 확보한다.",
      "릴리스 노트에 내부 수요일 스트레치 골을 언급할지 결정 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정되지 않은 제안은 결정사항으로 쓰지 않는다.",
    "거부된 제안은 확정 결정과 분리한다.",
    "내부 스트레치 골은 공개 릴리스 확정 일정과 분리한다.",
    "담당자나 마감이 없는 항목에는 임의로 owner나 deadline을 넣지 않는다."
  ]
}
